step.instructions:
Generates a Liberty server dump for zosmfServer.
Output will be written to: ${instance-DUMP_ARCHIVE}
Dump types included: ${instance-DUMP_INCLUDE}

template.inlineTemplate:
#!/bin/sh echo "Triggering Liberty javadump via operator command..." echo "Include : ${instance-DUMP_INCLUDE}" echo "-----------------------------------"
/usr/sbin/operator "F IZUSVR1,JAVADUMP" RC=$?
echo "-----------------------------------" echo "Operator command issued. RC=$RC" echo "Dump files will appear in: /global/zosmf/ZOS31/data/logs/zosmfServer" ls -lht /global/zosmf/ZOS31/data/logs/zosmfServer | head -5
